          Đời Sống Tình Dục?: {
            Phát Triển Cơ Thể: {
              Âm Đạo: string; // [(0%-100%) Đều không ít hơn 20 chữ mô tả (lộ liễu, táo bạo), áp dụng cho mọi bộ phận]
              Khuôn Mặt: string;
              Mông: string;
              Chân: string;
              Tay: string;
              Hậu Môn: string; // 
              Miệng: string; // 
              Ngực: string; // 
            };
            Tư Thế Ưa Thích: string; // Ghi lại tư thế đặc định mà NPC biểu hiện cao trào hoặc thuận tùng (mô tả 20 chữ)
            Dâm Văn: string; // NPC đều có Dâm Văn độc đáo, hiện lên ở bộ phận kín đáo (bụng dưới, lưng...) khi làm tình. Thay đổi theo số lần làm tình (mô tả 30 chữ)
            Độ Sa Ngã: string; // (0%-100%) Không ít hơn 20 chữ mô tả
            Cúp Ngực: string; // Có thể thay đổi theo cốt truyện hoặc cải tạo, hình dáng ngực mỗi nữ giới đều khác nhau, không ít hơn 20 chữ mô tả
            Sở Thích Tình Dục: Record<string, string>; // Như: {'Thuộc tính M': 'Đang thức tỉnh', 'Cuồng phô dâm': 'Đã cố hóa'} (mô tả 30 chữ)
            Đánh Giá Chung: string; // Không ít hơn 30 chữ mô tả (lộ liễu, trêu chọc)
